#include <stdio.h>
#include <string.h>

int atMostKDistinct(char *s, int k) {
    int left = 0, res = 0;
    int freq[26] = {0};

    for (int right = 0; right < strlen(s); right++) {
        freq[s[right] - 'a']++;

        while (countDistinct(freq) > k) {
            freq[s[left] - 'a']--;
            left++;
        }

        res += (right - left + 1);
    }
    return res;
}

int countDistinct(int *freq) {
    int count = 0;
    for (int i = 0; i < 26; i++) {
        if (freq[i] > 0) count++;
    }
    return count;
}

int countSubstrings(char *s, int k) {
    return atMostKDistinct(s, k) - atMostKDistinct(s, k - 1);
}

